const input = $input.item.json.body;

const phaseInfo = {
  engage: { label: 'Engage (引入)', description: '建立情感连接与情境导入，激发好奇心和参与动机' },
  empower: { label: 'Empower (赋能)', description: '输入语言知识与SEL技能，进行体感探索' },
  execute: { label: 'Execute (实践)', description: '通过艺术表达完成终极产出任务，体验合作分享' },
  elevate: { label: 'Elevate (升华)', description: '反思、内化并建立积极情绪闭环' }
};

const phaseKey = input.phaseKey || 'engage';
const info = phaseInfo[phaseKey];

let currentStepStr = '无';
if (input.currentStep) {
  const s = input.currentStep;
  currentStepStr = `ID: ${s.id}\n标题: ${s.title}\n时长: ${s.time}\n目标: ${s.objective || ''}`;
}

let siblingStepsStr = '无';
if (input.siblingSteps && input.siblingSteps.length > 0) {
  siblingStepsStr = input.siblingSteps.map((s, i) => `${i+1}. ${s.title} (${s.time})`).join('\n');
}

let otherPhasesStr = '无';
if (input.otherPhases) {
  try {
    otherPhasesStr = typeof input.otherPhases === 'string' ? input.otherPhases : JSON.stringify(input.otherPhases, null, 2);
  } catch (e) {
    otherPhasesStr = '无法解析';
  }
}

return {
  age: input.age || '7-9岁',
  duration: input.duration || '60分钟',
  scale: input.scale || '≤ 8人',
  title: input.title || '未命名课件',
  vocabulary: (input.vocabulary && input.vocabulary.length > 0) 
    ? (Array.isArray(input.vocabulary) ? input.vocabulary.join(', ') : input.vocabulary)
    : '请根据主题推荐词汇',
  grammar: (input.grammar && input.grammar.length > 0) 
    ? (Array.isArray(input.grammar) ? input.grammar.join(', ') : input.grammar)
    : '请根据主题推荐句型',
  theme: input.theme || '默认主题',
  requirements: input.requirements || input.userIdea || '',
  classicName: input.classicName || '',
  phaseKey: phaseKey,
  phaseLabel: info.label,
  phaseDescription: info.description,
  stepId: input.stepId || '',
  currentStep: currentStepStr,
  siblingSteps: siblingStepsStr,
  otherPhases: otherPhasesStr
};

parameters.text:
=# Role
你是一位拥有15年经验的资深儿童英语课程设计师，擅长将 SEL（社会情感学习）和 PERMA 幸福模型无缝融入英语教学。

# Task
请根据以下课程信息，为「{{ $json.phaseLabel }}」阶段重新生成一个教学步骤，替换当前步骤。新步骤必须与同阶段其他步骤以及整体叙事保持连贯。

# 课程信息
- 学生年龄：{{ $json.age }}
- 课程时长：{{ $json.duration }}
- 班级规模：{{ $json.scale }}
- 课程标题：{{ $json.title }}
- 核心词汇：{{ $json.vocabulary }}
- 核心句型：{{ $json.grammar }}
- 情境主题：{{ $json.theme }}
- 特殊要求：{{ $json.requirements }}

# 本阶段信息
- 阶段名称：{{ $json.phaseLabel }}
- 阶段定位：{{ $json.phaseDescription }}

# 当前要替换的步骤
{{ $json.currentStep }}

# 同阶段其他步骤（保持叙事连贯）
{{ $json.siblingSteps }}

# 其他阶段（保持整体叙事一致）
{{ $json.otherPhases }}

# Step 字段规范
生成的步骤必须包含以下字段：
- `id`: 固定为 "{{ $json.stepId }}"
- `time`: 具体时长，如 "5-10分钟"
- `title`: 环节标题，富有想象力和故事感，与整体叙事一致
- `objective`: 教学目标，必须同时包含语言目标和 SEL 目标
- `activity`: 活动描述，包含具体的活动流程、师生互动方式、分组形式等
- `activitySteps`: 结构化的课堂执行流程，按真实上课顺序拆分为4个步骤。每行格式为"步骤名称：活动内容描述"，用换行分隔，例如"创设悬念：教师展示一张神秘的地图，引导学生猜测各种水果。\n朗读来信：教师朗读水果的英文名称，让学生跟读。\n情绪感知：教师让学生通过面部表情表现对不同水果的感受。\n发布任务：分组完成任务，并展示成果。"
- `script`: 教师讲稿，亲切、有感染力，符合7-9岁儿童心理特征，中英文穿插（讲稿主体为中文，指令性语言带英文），必须包含情境创设内容
- `resources`: 教学资源清单，用顿号或逗号分隔，例如"任务卡、图片卡、计时器、奖励贴纸"
- `scenario`: 简短的情境创设描述（一句话），例如"教室变为神秘的森林入口，学生以探险队身份迎接任务挑战。"
- `assets`: 教学资源数组，包含 1 个资源：`{ "id": "asset-{{ $json.stepId }}", "type": "image", "title": "资源名称", "prompt": "生图提示词" }`
- `assets[].prompt` 必须严格遵守：扁平矢量插画，粗细均匀的黑色轮廓线，单线风格，2D扁平设计，无渐变，无阴影，低饱和度的平涂色彩、和谐的柔和色调、连贯的配色方案，简化但风格化的背景，清晰的环境线稿，非写实扁平插画，干净亲和的美学，沉浸式叙事扁平背景，画面无人物无文字

# Style Requirements
- 教师讲稿：亲切、富有感染力，中英文穿插
- 生图提示词：严格遵守扁平矢量插画的特定美学风格

# Output Constraint（严格遵守！少一个字段都会导致前端报错）
你必须输出一个完整的 JSON 对象，包含以下全部字段，缺一不可：
{
  "step": {
    "id": "{{ $json.stepId }}",
    "time": "6-10分钟",
    "title": "富有想象力的环节标题",
    "objective": "语言目标：...；SEL目标：...",
    "activity": "该环节的活动描述（约150-300字）",
    "activitySteps": "创设悬念：第一步的描述\n朗读来信：第二步的描述\n情绪感知：第三步的描述\n发布任务：第四步的描述",
    "script": "该环节的教师讲稿（亲切、中英文穿插）",
    "resources": "任务卡、图片卡、计时器、奖励贴纸",
    "scenario": "教室变为神秘的森林入口，学生以探险队身份迎接任务挑战。",
    "assets": [
      {
        "id": "asset-{{ $json.stepId }}",
        "type": "image",
        "title": "资源名称",
        "prompt": "扁平矢量插画，粗细均匀的黑色轮廓线..."
      }
    ]
  }
}
- 以上 12 个字段（id, time, title, objective, activity, activitySteps, script, resources, scenario, assets）一个都不能少
- 严禁包含任何 Markdown 代码块标签或首尾解释性文字
- 直接输出上述 JSON，不要用 ```json 包裹

