// 解析 LLM 输出的 JSON 文本
let raw = $input.item.json;

// 如果 LLM 输出有 text 字段，从中提取 JSON
if (raw.text && typeof raw.text === 'string') {
  const match = raw.text.match(/\{[\s\S]*\}/);
  if (match) {
    try { raw = JSON.parse(match[0]); } catch (e) {}
  }
}

const step = (raw.step && typeof raw.step === 'object') ? raw.step : raw;

// 补充 activitySteps
if (!step.activitySteps || step.activitySteps.trim() === '') {
  const activity = step.activity || '';
  const sentences = activity.split(/[。！？]+/).filter(s => s.trim());
  const stepNames = ['创设悬念', '朗读来信', '情绪感知', '发布任务'];
  const size = Math.ceil(sentences.length / 4);
  const parts = [];
  for (let i = 0; i < 4; i++) {
    const chunk = sentences.slice(i * size, (i + 1) * size);
    parts.push(stepNames[i] + '：' + (chunk.length > 0 ? chunk.join('。') + '。' : ''));
  }
  step.activitySteps = parts.join('\n');
}

// 补充 resources（从 assets[].title 提取）
if (!step.resources || step.resources.trim() === '') {
  const assets = Array.isArray(step.assets) ? step.assets : [];
  step.resources = assets.map(a => a.title || '').filter(Boolean).join('、');
}

// 补充 scenario（从 activity 第一句截取）
if (!step.scenario || step.scenario.trim() === '') {
  const activity = step.activity || '';
  const first = activity.split(/[。！？]/)[0] || '';
  step.scenario = first.length > 60 ? first.slice(0, 60).replace(/[，、]$/, '') : first;
}

return { step: step };
